import javax.xml.parsers.*;
import org.w3c.dom.*;   // This is a standard Java library that parses XML documents by converting them into DOM (Document Object Model) trees of objects, so they can be navigated and manipulated as if the document was in memory – which are very useful when working with large or complex data sets
import javax.xml.XMLConstants;   // This is a standard Java library that provides constants for XML namespaces to avoid any potential conflicts due namespace declarations (i.e., xmlns:xsi) and default rules about how attributes should be handled in an element, like "required", so this will prevent such issues
import org.xml.sax.*;  // This is a standard Java library that parses XML documents by converting them into DOM trees of objects using the SAX (Simple API for XML - Asynchronous XML) style parser interface and includes features to handle errors in an easy way, like how unexpected elements can be gracefully handled
import org.xml.sax.helpers.*;  // This is a standard Java library that provides classes or interfaces so you don't need the client code know about these details of their internal workings (they only use interface declarations) if they aren’t going to make direct calls on them during runtime
import java.net.*;   // In order for this program, we will require URLConnection and BufferedReader classes which are standard Java libraries that allow us a great deal more flexibility in creating HTTP requests from the command line with simple syntax than using HttpURLConnection or FileStreams (for example).